CREATE OR REPLACE VIEW `vplantactivecurrentlocation` AS select `p`.`plantId` AS `plantId`,`t`.`taxonId` AS `taxonId`,`p`.`plantTag` AS `plantTag`,`p`.`plantName` AS `plantName`,`g`.`genusName` AS `genusName`,`g`.`isActive` AS `genusIsActive`,`t`.`isActive` AS `taxonIsActive`,`loc`.`locationId` AS `locationId`,`loc`.`locationName` AS `locationName`,`loc`.`locationTypeCode` AS `locationTypeCode`,`plh`.`startDateTime` AS `locationStartDateTime`,(case when (`t`.`isSystemManaged` = 1) then concat(`g`.`genusName`,' sp.') when (`t`.`speciesName` is not null) then concat(`g`.`genusName`,' ',`t`.`speciesName`) when (`t`.`hybridName` is not null) then concat(`g`.`genusName`,' ',`t`.`hybridName`) else `g`.`genusName` end) AS `displayName`,`pp`.`filePath` AS `heroFileName` from (((((`plant` `p` join `taxon` `t` on((`t`.`taxonId` = `p`.`taxonId`))) join `genus` `g` on((`g`.`genusId` = `t`.`genusId`))) left join (select `sub`.`plantId` AS `plantId`,`sub`.`locationId` AS `locationId`,`sub`.`startDateTime` AS `startDateTime` from (select `lochistory`.`plantId` AS `plantId`,`lochistory`.`locationId` AS `locationId`,`lochistory`.`startDateTime` AS `startDateTime`,row_number() OVER (PARTITION BY `lochistory`.`plantId` ORDER BY `lochistory`.`startDateTime` desc )  AS `RowOrder` from `plantlocationhistory` `lochistory` where (`lochistory`.`isActive` = 1)) `sub` where (`sub`.`RowOrder` = 1)) `plh` on((`p`.`plantId` = `plh`.`plantId`))) left join `location` `loc` on(((`loc`.`locationId` = `plh`.`locationId`) and (`loc`.`isActive` = 1)))) left join `plantphoto` `pp` on(((`pp`.`plantId` = `p`.`plantId`) and (`pp`.`isHero` = 1) and (`pp`.`isActive` = 1)))) where ((`p`.`isActive` = 1) and (`p`.`endDate` is null));

